import numpy as np

def smoothclamp(x, min_val, max_val, N=3):
    x = np.Array(x)
    if max_val == min_val:
        return np.Array(min_val)
    if x < min_val:
        return np.Array(min_val)
    if x > max_val:
        return np.Array(max_val)

    t = np.Array((x - min_val) / (max_val - min_val))

    # Smoothstep formula: smooth_step(t) = 3t^N - 2t
    smooth = min_val + (max_val - min_val) * (3 * t ** N - 2 * t)
    return np.Array(smooth)
