import numpy as np

def clean_gray_image_array(arr):
    if arr.ndim != 2:
        return np.zeros((0, 0))
    arr_copy = arr.copy()
    # Remove first zero row
    while np.all(arr_copy[0] == 0):
        arr_copy = arr_copy[1:, :]
    # Remove last zero row
    while np.all(arr_copy[-1] == 0):
        arr_copy = arr_copy[:-1, :]
    # Remove first zero column
    while np.all(arr_copy[:, 0] == 0):
        arr_copy = arr_copy[:, 1:]
    # Remove last zero column
    while np.all(arr_copy[:, -1] == 0):
        arr_copy = arr_copy[:, :-1]
    return arr_copy
